INSERT INTO scenarios (id, slug, category, title, description) VALUES
('03c02bb5-b765-4e16-81b6-383235b08226', 'the-pile-on-social-soc-socialcasc-0', 'social', 'The pile-on (social)', 'A friend is being dogpiled in the group chat over something half-true. Speaking up draws fire; staying quiet feels like complicity.'),
('04030748-2eca-4ed6-b61c-b0e1e6afb5b0', 'public-callout-social-soc-socialcasc-1', 'social', 'Public callout (social)', 'Someone criticizes your decision in front of the whole group, and all eyes turn to you. Defending looks defensive; conceding looks weak. There is no clean option.'),
('2cb72fb6-f1e5-4552-b0de-4ef6e363f865', 'exclusion-social-soc-socialcasc-2', 'social', 'Exclusion (social)', 'You learn the group made plans without you and did not think to mention it. Raising it seems needy; swallowing it seeds resentment.'),
('ea9abfcc-8265-451c-946a-f09e40872f1d', 'awkward-reunion-social-soc-socialcasc-3', 'social', 'Awkward reunion (social)', 'You run into someone you have not fully patched things up with, in front of people who do not know the history. Everyone is watching how normal you can make this look. Everyone is watching how you handle it.'),
('ca3e0d22-65ff-4b80-b294-145f9cd13760', 'exclusion-social-soc-socialcasc-4', 'social', 'Exclusion (social)', 'You learn the group made plans without you and did not think to mention it. Raising it seems needy; swallowing it seeds resentment.'),
('a03f4015-fbce-47e5-9573-e9cb64afb8a4', 'apology-demanded-social-soc-socialcasc-5', 'social', 'Apology demanded (social)', 'You are asked to apologize publicly for something you do not fully believe you did wrong. The crowd wants contrition; your conscience does not. There is no clean option.'),
('14760da2-922d-4118-acbd-0d831f388518', 'loyalty-test-social-soc-socialcasc-6', 'social', 'Loyalty test (social)', 'Two people you care about are feuding and each expects you to pick a side. Neutrality reads as betrayal to both. The clock is running.'),
('890140b2-d695-4e7d-a842-624cb12688f6', 'group-chat-archaeology-social-soc-socialcasc-7', 'social', 'Group chat archaeology (social)', 'Someone digs up an old message of yours and reads it in the worst possible light to the group. Context helps but sounds like an excuse. The clock is running.'),
('1dffe8f1-64fa-4520-8780-6df681af0601', 'group-chat-archaeology-social-soc-socialcasc-8', 'social', 'Group chat archaeology (social)', 'Someone digs up an old message of yours and reads it in the worst possible light to the group. Context helps but sounds like an excuse. There is no clean option.'),
('98accc95-c29f-47df-b001-53bcccd4e0c7', 'boundary-crossed-social-soc-socialcasc-9', 'social', 'Boundary crossed (social)', 'Someone repeatedly oversteps a line you never quite drew out loud. Naming it invites conflict; tolerating it invites more. Everyone is watching how you handle it.'),
('d6f945dd-e1ee-4617-a0f6-edc0589d519a', 'uneven-friendship-social-soc-socialcasc-10', 'social', 'Uneven friendship (social)', 'You realize, all at once, that you have been putting more effort into this friendship than the other person has for a long time.'),
('c2071c16-f465-42b9-84e7-47661df9063d', 'apology-demanded-social-soc-socialcasc-11', 'social', 'Apology demanded (social)', 'You are asked to apologize publicly for something you do not fully believe you did wrong. The crowd wants contrition; your conscience does not. The clock is running.'),
